INSERT INTO public.photos VALUES (24587, 'Lonja de Mercaderes. Interior. 1885', 'A.M.Z. Sign. 0913. La Lonja, Zaragoza. [1885] Magn├¡fico edificio civil renacentista que albergaba las reuniones de los pr├│ceres mercantiles de la ciudad (1551). Hoy sigue en pie en la plaza del Pilar, mostrando exposiciones municipales.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65577200, -0.87651500, '0101000020E610000095826E2F690CECBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858893205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858893205.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858893205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24590, 'Lonja c.1877', 'Jean Laurent, "Zaragoza-La Lonja". Al principio de la antigua calle de la Cuchiller├¡a, otra de las im├ígenes de la Lonja capturadas por Jean Laurent, en tiempos en que era utilizada como espacio para actos p├║blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no pod├¡an pagarse el no hacerlo), y algunas representaciones teatrales. A su derecha, y pegado, el edificio de la Casa Consistorial levantado unas d├®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden d├│rico. Fuente: "Mirar el mundo otra vez. 25 a├▒os de fotograf├¡a en la galer├¡a Spectrum".', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16610030380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16610030380.webp', 'https://www.flickr.com/photos/zaragozaantigua/16610030380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24593, 'Puerta del ├üngel c.1865', 'Vista de la ├║ltima versi├│n de la Puerta del ├üngel, con la Lonja en primer plano a la izquierda, seguida de las casas consistoriales. Fuente: Instant├íneas zaragozanas, CAMPZAR, 1982.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24865007091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24865007091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24865007091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24595, 'La Lonja 1991', 'Imagen de la escultura en bronce titulada "Caballito", con posado de su autor, el modelista Francisco Rallo Lahoz, en las traseras de la Lonja. El bronc├¡neo equino fue concebido como homenaje de la ciudad al fot├│grafo Angel Cordero Gracia, que ejerci├│ de "minutero" en los jardines de la plaza de la Lonja recayentes al paseo del Ebro, entre 1925 y 1978, en el entorno donde fue ubicado este bulto redondo. El original caballito era de cart├│n piedra, y en ├®l se sentaban las ni├▒as y ni├▒os que iban a ser retratados. Posiblemente esta imagen fuera capturada en la inauguraci├│n oficial de esta obra. Fuente visual: Antonio Calvo Pedr├│s, AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30491155170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30491155170.webp', 'https://www.flickr.com/photos/zaragozaantigua/30491155170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24596, 'La Lonja c.1902', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n┬║ 134 de las im├ígenes de "Zaragoza" incluidas en la serie postal de Espa├▒a para la Uni├│n Postal Universal, que captura una vista canicular de la Lonja desde cierta altura, en la arbolada plaza de la Seo. A la izquierda, la ensanchada esquina del final de la calle del Pilar. A la derecha, en la calle de Don Fernando el Cat├│lico, la Casa del Ayuntamiento. Al fondo, el puente de Piedra y casas del Arrabal. Fuente visual: www.todocoleccion.net/', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33908400994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33908400994.webp', 'https://www.flickr.com/photos/zaragozaantigua/33908400994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24598, 'La Lonja c.1892', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n┬║ 287 entre las im├ígenes de "Zaragoza" incluidas en la serie postal de Espa├▒a, que captura una vista de la Lonja desde la zona de sombra ma├▒anera de la plaza de la Seo. A la izquierda, la esquina del final de la calle del Pilar. A la derecha, las Casas de la Ciudad, o ayuntamiento. En la plaza, a la derecha, e inmediatas, un grupo de mujeres se abastecen de agua en la fuente de la Samaritana (fuera de plano). Fuente visual: www.todocoleccion.net/', 1892, 1892, 1892, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34673697456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34673697456.webp', 'https://www.flickr.com/photos/zaragozaantigua/34673697456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24599, 'La Lonja 1844', '"Sal├│n de la Lonja", como parte integrante de las Casas de la Ciudad, o Ayuntamiento. Fuente visual: "Recuerdos y Bellezas de Espa├▒a. Obra destinada a dar a conocer sus monumentos, antig├╝edades y vistas pintorescas en l├íminas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa├▒adas de texto por P. Piferrer y J. M. Quadrado. Arag├│n: Jos├® Mar├¡a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34737152251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34737152251.webp', 'https://www.flickr.com/photos/zaragozaantigua/34737152251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24600, 'Marqu├®s de Almenara 1591', '"El pueblo zaragozano hiere al marqu├®s de Almenara". Ilustraci├│n de F. Blanch que recrea el ataque de algunos ciudadanos en 1591 contra ├ì├▒igo Hurtado de Mendoza y de la Cerda, marqu├®s de Almenara, enviado por Felipe II a Zaragoza en 1588. Muri├│ en la c├írcel dos semanas despu├®s. Al fondo, la calle del Pilar, la Lonja y las casas consistoriales. A la derecha, fragmento de la Diputaci├│n del Reino en la plaza de la Seo. Fuente visual: Historia de Espa├▒a, Miguel Segu├¡, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65548300, -0.87641700, '0101000020E6100000E01115AA9B0BECBFBF0AF0DDE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40204809215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40204809215.webp', 'https://www.flickr.com/photos/zaragozaantigua/40204809215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24601, 'Plaza del Pilar 1981', 'Imagen capturada en la plaza del Pilar junto al ingreso principal a la Lonja, escenario de la Exposici├│n "50 aniversario del Cuerpo de Bomberos de Zaragoza", donde se conmemoraba a constituci├│n de este Cuerpo como servicio profesional de extinci├│n de incendios a cargo del Ayuntamiento en el a├▒o 1931. El veh├¡culo de primer t├®rmino formaba parte de la exposici├│n de material hist├│rico de bomberos, y se trata de un cami├│n que transportaba una escalera m├│vil Magirus E-1 que estuvo en servicio desde 1937 y hasta 1966. Se considera que el ├®xito de esta exposici├│n fue el germen del Museo del Fuego inaugurado en 2012.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50143937168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50143937168.webp', 'https://www.flickr.com/photos/zaragozaantigua/50143937168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24605, 'Plaza de la Seo 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Marzo 1974. Imagen de la Plaza de la Seo desde la calle Don Jaime. La fuente que aparece fue la que sustituy├│ a la de La Samaritana, cuando fue desmontada y trasladada, primero al Parque Bruil, luego a la Plaza del Justicia. M├ís tardes, a finales de los a├▒os 80, la Plaza de la Seo hab├¡a alcanzado un lamentable estado que llev├│ a redactar un proyecto de remodelaci├│n que inclu├¡a el regreso de La Samaritana, pero el hallazgo de los restos del Foro Romano obligaron a transformar el proyecto en lo que hoy vemos.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65551100, -0.87642200, '0101000020E610000052D66F26A60BECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14718879029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14718879029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14718879029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24608, 'La Seo a├▒os 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. [Plaza del Pilar] La Torre de la Seo [o La Catedral del Salvador en su Epifan├¡a y Puerta de San Bartolom├® en la fachada principal o neoc├ísica]". Imagen tomada desde la calle el Pilar. Fuente visual: Archivo W├╝nderlich (WUN-05810) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65570300, -0.87679200, '0101000020E6100000309FAC18AE0EECBFCE716E13EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877342207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877342207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877342207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24612, '├üngel Cordero Gracia 1974', '├üngel Cordero Gracia ejerci├│ de fot├│grafo minutero desde 1925, retratando ni├▒os y ni├▒as sobre un caballito de madera en los jardines traseros de la Lonja. Era Minutero porque entre el posado, la instant├ínea, y el revelado, se suced├¡an escasos minutos, una pr├íctica que estuvo realizando hasta 1978, y por la que pasaron varias generaciones de j├│venes, y no tan j├│venes, bien locales, o de paso por la ciudad. En 1991 el Ayuntamiento homenaje├│ su memoria instalando, en el mismo espacio donde estuvo trabajando tanto tiempo, una escultura en bronce sobre pedestal circular de granito rosa, obra de Francisco Rallo Lahoz, que representa al caballito protagonista de tantas instant├íneas. En la imagen, ├üngel Cordero se encamina, cargado con sus herramientas de trabajo recogidas en la plaza de San Bruno n┬║ 3, hacia la Lonja cruzando por la plaza de La Seo. El objetivo de la c├ímara, aun cubierto, nos observaÔÇª', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65551100, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15047796462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15047796462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15047796462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24627, 'Calle del Pilar 1920', 'Foto: Julio Requejo. Aspecto de la calle del Pilar con la Seo al fondo, en junio de 1920. La imagen ha sido volteada horizontalmente para su correcta visualizaci├│n. Fuente: DARA/AHPZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21193339789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21193339789.webp', 'https://www.flickr.com/photos/zaragozaantigua/21193339789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24658, 'Plaza de La Seo c.1942', 'Imagen capturada desde la altura del inmueble del n┬║ 19 de la antigua calle del Pilar antes de su derribo para despejar de viejas casonas el tramo m├ís oriental de la ampliada plaza del Pilar, y dejar espacio a la nueva Casa Consistorial. Inmediata y a la izquierda, la Lonja, y al fondo, la plaza de La Seo. A la derecha y fuera de plano, el despejado solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65578300, -0.87694200, '0101000020E610000083A44FABE80FECBFEA2285B2F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49305726783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49305726783.webp', 'https://www.flickr.com/photos/zaragozaantigua/49305726783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25198, 'Puerta del ├üngel 1851', '"Dibujos que representan dos proyectos para la Puerta del ├üngel de esta Ciudad, arreglados ├í lo mandado por M. II. SS. Gobernador de la Provincia, y Alcalde Corregidor de esta Capital". Zaragoza, 12 de septiembre de 1851. Ninguno de los dos proyectos de esta puerta, entre las Casas Consistoriales y el Seminario Conciliar, fue levantado. En 1860 se erigi├│ otro modelo, obra de Miguel Jeliner y Germ├í. Fuente: AMZ.', 1851, 1851, 1851, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126168596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126168596.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126168596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25650, 'Don Jaime I c.1925', 'Archivo Municipal de Zaragoza. "Procesi├│n religiosa" en la que, aunque as├¡ lo parezca, quien va solemne bajo palio no es el tranv├¡a de la L├¡nea "Arrabal". Imagen tomada en la calle Don Jaime, con la Lonja a la izquierda, y la plaza de la Seo a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65562200, -0.87640700, '0101000020E6100000FD885FB1860BECBFE144F46BEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964558620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964558620.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964558620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25671, 'Don Jaime I, c.1925', '"Zaragoza II. [La Lonja]". Captura visual del entronque de la calle de don Jaime I, la calle del Pilar, a la izquierda, y la arbolada plaza de la Seo, a la derecha. Al fondo, el puente de Piedra. Vertebra la imagen el sencillo e imponente edificio de la antigua Lonja de mercaderes, ya despejada de las derribadas Casas de la Ciudad. A la izquierda, el antiguo n┬║ 6 de la calle Don Jaime I, derribado durante la radical creaci├│n de la gran plaza del Pilar. Incrustados en el firme, los ra├¡les tranviarios de las ya electrificadas l├¡neas "Arrabal" y "G├íllego". La circulaci├│n rodada, fluida. Fuente visual: Archivo del Conde de Polentinos (Aurelio de Colmenares y Orgaz), Fototeca del Patrimonio Art├¡stico', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785373001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785373001.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785373001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25673, 'Don Jaime I, 1968', 'Imagen de la unidad n┬║ 164 (serie 150, o topolinos), de la l├¡nea tranviaria 4 ("Arrabal") encaminada hacia la plaza de la Seo. Esta unidad se activaba cuando las dos tranv├¡as "oficiales" de la l├¡nea (el 223, y el 228) estaban averiados, como parece ser el caso. A la izquierda, el acceso desde el puente de Piedra. Detr├ís, el multifuncional edificio del arzobispado, antiguo Seminario Conciliar, ahora ocupado, entre otros, por Radio Popular, y por el cine Pax. A la derecha, quiosco y densa arboleda de la plaza de la Seo. Fuente visual: trotskeetravel.com/, a trav├®s de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170380711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170380711.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170380711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25676, 'Lonja c.1925', 'Imagen de la Lonja, despejada de las antiguas Casas de la Ciudad (ayuntamiento), estrat├®gica entre las calles de don Jaime I y del Pilar, y el paseo del Ebro. Fuente visual: "Casa Lonja. Exterior", en ÔÇ£El arte en Espa├▒a. Zaragoza, con texto de Anselmo Gasc├│n de Gotor. Edici├│n Thomas. Patronato Nacional de Turismo.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33515081093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33515081093.webp', 'https://www.flickr.com/photos/zaragozaantigua/33515081093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25683, 'Calle de Don Jaime I 1968', 'Veraniega imagen capturada en la calle de Don Jaime I ( (original cardo de la Cesaraugusta romana) y centrada en el troleb├║s n┬║ 14 modelo BUT London (ubicaci├│n del volante a la diestra) de un piso realizando el trayecto de regreso en la l├¡nea G├íllego y en direcci├│n al tramo medio del Coso. De fondo edilicio, el antiguo seminario metropolitano, que entonces albergaba diversas dependencias del arzobispado, como Radio Popular y el cine Pax (que reestrenaba la comedia "Tres en un sof├í"), am├®n de la sucursal de una importante local caja de ahorros. Hacia la derecha se abre la plaza de La Seo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65552700, -0.87653500, '0101000020E61000005B94D920930CECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51570599902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51570599902.webp', 'https://www.flickr.com/photos/zaragozaantigua/51570599902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20883, 'La Seo s. XIV', 'Dibujo de Francisco ├ì├▒iguez, 1937. La recreaci├│n representa el templo en su ├®poca mud├®jar. La tesis oficial no contempla que la actual torre barroca utilizara el emplazamiento del alminar octogonal de la mezquita mayor de Saraqusta, pero algunos investigadores sostienen esa opci├│n. Fuente: sites.google.com/site/zagralandalus/los-alminares-de-la-seo, a trav├®s de www.facebook.com/photo.php?fbid=1864645023755215&set=...', 1350, 1300, 1399, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65524300, -0.87609700, '0101000020E610000073F56393FC08ECBF6AF7AB00DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30682686311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30682686311.webp', 'https://www.flickr.com/photos/zaragozaantigua/30682686311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20891, 'Gran Cloaca ca. 20', 'La ┬½Gran Cloaca┬╗ del foro romano de Caesaraugusta resurgi├│ al levantar en 1982 la plaza de La Seo. Un siglo antes (1870) ya se dio con ella. Hoy se encuentra conservada como una estructura m├ís del Museo del Foro de Caesaraugusta. Fue realizada a finales del reinado de Augusto, o comienzos del de Tiberio, entre el a├▒o 10 y el 20 de la Era, como parte del sistema de saneamiento y evacuaci├│n de aguas del nuevo foro. Construida en opus caementicium, se cubri├│ con b├│veda de medio ca├▒├│n. La altura interior es de 2.64 m. y la luz de 1.78 m. El espesor de las paredes es de 60 cm. En la imagen, vista parcial de los restos de la "Gran Cloaca" al aire en la plaza de la Seo. Archivo Luis Serrano. Fuente: "El Ebro", Ediciones Oroel, 1986.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16814002841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16814002841.webp', 'https://www.flickr.com/photos/zaragozaantigua/16814002841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21138, 'Plaza de La Seo c.1895', '"Vista de la Catedral de San Salvador (La Seo)", y de la Plaza de la Seo, desde altura. Fuente visual: Esudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65516600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFBFB9BF7ADCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14745087029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14745087029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14745087029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21139, 'Plaza de La Seo c.1895', 'Vista de la Lonja de mercaderes desde la plaza de La Seo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65519000, -0.87621800, '0101000020E61000003354C554FA09ECBF47551344DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750916237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750916237.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750916237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21150, 'Plaza de La Seo c.1895', '"La Lonja". Foto Colecci├│n Universidad Michel de Montaigne, Burdeos. Toma de la plaza de la Seo de Zaragoza, mirando hacia la Lonja, cuando el antiguo edificio de viviendas (esquina entre la calle del Pilar y Don Jaime, a la izquierda) a├║n estaba intacto. A la derecha, edificio del arzobispado. La fuente de la Samaritana, con utilidad no s├│lo est├®tica. Mediados de la d├®cada de 1890. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704539937.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704539937.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704539937/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21166, 'Plaza de La Seo c.1895', 'Imagen de la plaza de la Seo centrada en la fuente de la Samaritana cuando era el acu├ítico epicentro de una notable foresta, y a su funci├│n est├®tica se un├¡a la funcional de proveedora de agua. Hab├¡a sido instalada en 1866. A la izquierda, la Lonja y la Casa Consistorial. Enfrente, tras la de Samaria, el Seminario Conciliar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23025287529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23025287529.webp', 'https://www.flickr.com/photos/zaragozaantigua/23025287529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21198, 'Plaza de La Seo 1890', 'Coloreada imagen capturada desde la altura del inmueble del n┬║ 3 de la plaza de La Seo con una interesante vista de la antigua plaza y su entorno, dominado por la esbelta torre barroca de la catedral del Salvador en su Epifan├¡a y su clasicista fachada que decora el ingreso por la puerta occidental del templo. A la izquierda, el Arco del Arzobispo que comunica con el hom├│nimo palacio. La plaza aparece vertebrada alrededor, en primer t├®rmino, de la fuente de la Samaritana, realizada en la fundici├│n Averly.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65534200, -0.87643800, '0101000020E6100000BE175FB4C70BECBFFDD8243FE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425457922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425457922.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425457922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21241, 'Calle Don Jaime c.1900', 'Grupo de tres hombres caminando tranquilamente por la calle de Don Jaime I de Zaragoza. Al fondo, el cruce con la calle del Pilar y la Lonja. Fuente: www.facebook.com/photo.php?fbid=1668897606655861&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894433228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894433228.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894433228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21242, 'Plaza de La Seo c.1900', 'Plaza de La Seo de Zaragoza, vista desde la calle de Don Jaime I. A la izquierda, el Palacio Arzobispal y el Arco del Arzobispo. En el centro, la estatua de la Samaritana ante la catedral. Fuente: www.facebook.com/photo.php?fbid=1668896829989272&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057509096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057509096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057509096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22482, 'Av. Compromiso de Caspe 1962', 'Tranquila imagen capturada en el antiguo camino de las Fuentes, ya redenominado como avenida del Compromiso de Caspe y centrada en el tramo de los impares (a la derecha) entre las recientes calles Doctor Iranzo y Obispo Laplana, poco antes de Salvador Minguij├│n, que entonces se├▒alaba el "nec plus ultra" de la ciudad en esta perif├®rica barriada. Hacia el fondo de la imagen, el lejano principio de la avenida desde la calle de Miguel Servet. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64538000, -0.86299400, '0101000020E61000007C9DD497A59DEBBF0ABFD4CF9BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39282866304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39282866304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39282866304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23647, 'Aer├│dromo Sanjurjo 1939', 'El Aer├│dromo Sanjurjo, en Garrapinillos, fue habilitado como base a├®rea a comienzos de 1937 por los nacionalistas, en un estrat├®gico emplazamiento desde el que poder intervenir r├ípidamente en los principales frentes de guerra. En ├®l se aposent├│ importante n├║mero y calidad de aviones de la Legi├│n C├│ndor alemana, y de la Legionaria italiana. Fue tal su importancia, que en octubre de 1937 un escuadr├│n de "Chatos" y "Moscas" republicanos lo atacaron, destruyendo y da├▒ando entre 17 y 30 aviones de los facciosos. En la imagen, una l├¡nea de cazas Fiat CR-32 de la Aviaci├│n Legionaria Italiana, en los ├║ltimos d├¡as de la guerra. Al fondo, un polivalente Ju-52 y un bombardero He-111 de la Legi├│n C├│ndor. A├▒os despu├®s, a los aviones alemanes e italianos se les a├▒adir├¡an los de la fuerza a├®rea de los Estados Unidos de Norteam├®rica. Fuente visual: www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18009158285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18009158285.webp', 'https://www.flickr.com/photos/zaragozaantigua/18009158285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21335, 'Plaza de La Seo 1903', 'Grabado que recoge el paso del Rosario que, proveniente de la calle de Don Jaime I, da una vueltecilla a la plaza de la Seo para encaminarse luego a la calle del Pilar la noche del 18 de octubre de 1903, en el marco de la visita a Zaragoza del rey Alfonso XIII, que presidi├│ su paso desde el balc├│n central del Palacio Arzobispal (a la izquierda) habilitado como morada real durante su estancia de tres d├¡as. La plaza de La Seo y la fachada del palacio fueron iluminadas para tal ocasi├│n por la compa├▒├¡a Electro Peral Zaragozana. En el centro de la escena aparece la carroza titulada "la Venida de la Virgen", tallada en madera por el escultor Francisco de Borja ese mismo a├▒o y que hac├¡a aqu├¡ su estreno, siendo la ├║nica figura de este Rosario que no es de cristal. Aparece portada por 32 j├│venes con t├║nicas blancas y escoltados por todos los ac├│litos de los templos de Zaragoza que portaban pebeteros en los que se quemaba incienso y mirra. Tras ella, la carroza que representa a la bas├¡lica del Pilar, creada por Policarpo Valero y Bernab├® y ampliado a las cuatro torres en 1895 por Le├│n Quintana y Bianchi. A la derecha, vista de uno de los dos faroles con forma de le├│n, obra del taller de hojalateros y vidrieros de los Tiesto y construido en 1865-1866.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65527000, -0.87635200, '0101000020E61000001A187959130BECBF64062AE3DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52539891386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52539891386.webp', 'https://www.flickr.com/photos/zaragozaantigua/52539891386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21358, 'Plaza de La Seo 1900', 'Imagen centrada en la fachada occidental de la Seo, flanqueada por el Arco del Arzobispo a la izquierda y la torre del templo. La escena incluye una vista parcial de la plaza de La Seo y, en primer t├®rmino, el empedrado paso peatonal por el arranque de la calle de Don Jaime I, donde destaca el tendido tranviario que por 10 c├®ntimos y desde la plaza de la Constituci├│n conduce hacia la izquierda al Arrabal por el Puente de Piedra.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785682811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785682811.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785682811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21363, 'Plaza de La Seo c.1910', 'AHPZ-Archivo Coyne, 1907-1930. Plaza de la Seo.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65509400, -0.87628300, '0101000020E6100000F94D61A5820AECBF25E7C41EDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877890581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877890581.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877890581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21744, 'La Seo 1938', 'Tras dos a├▒os de ocultamiento por parte del bando franquista, en 1938 se revel├│ la muerte de Jos├® Antonio Primo de Rivera, l├¡der de la Falange fusilado en Alicante el 20 de noviembre de 1936. En la imagen, profusi├│n de coronas de flores al pie de la torre de la Seo, con motivo del funeral celebrado en noviembre de 1938 en memoria del pol├¡tico fascista. Fuente: Archivo Heraldo de Arag├│n.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21841817375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21841817375.webp', 'https://www.flickr.com/photos/zaragozaantigua/21841817375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21772, 'Plaza La Seo 1932', 'Plaza de la Seo y Fuente de la Samaritana. Al fondo, el Pilar. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854992097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854992097.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854992097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21814, 'Calle Pabostr├¡a 1934', 'Imagen de la procesi├│n del Domingo de Ramos 25 de marzo de 1934, reproducida en la revista Blanco y Negro en abril de 1935. Los palmeros desfilan por la calle de la Pabostr├¡a, con la de Diego Dormer al fondo. Fuente: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65444100, -0.87617200, '0101000020E61000001C78B5DC9909ECBFAD1402B9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30702428252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30702428252.webp', 'https://www.flickr.com/photos/zaragozaantigua/30702428252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21965, 'Plaza del Pilar 1949', 'Imagen de la despejada plaza del Pilar en su reciente ampliaci├│n por derribo entre Don Jaime I (izquierda), y el edificio del Gobierno Civil en construcci├│n (a la derecha, fuera de plano). La imagen se ha capturado desde la puerta de la Lonja. Enfrente, el nuevo edificio del n┬║ 16 de la plaza, esquinero con Don Jaime I, el primero de los tres de ese tramo. A su derecha, las traseras de los nuevos 25 y 27 de la calle Santiago, y por el solar del 23, visual de las antiguas viviendas a├║n sin derribar del 30-32, a la derecha del Palacio de Montemuzo. En la plaza, autobuses de l├¡nea regular entre Zaragoza y el entorno municipal y provincial. Fuente Visual: Fotos Ysa, Archivo P├║blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65541700, -0.87696300, '0101000020E610000061AA99B51410ECBF081F4AB4E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22177307702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22177307702.webp', 'https://www.flickr.com/photos/zaragozaantigua/22177307702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22081, 'Calle Pabostr├¡a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostria, capturada desde su arranque en la calle Dormer n┬║ 8. A la izquierda, la Puerta Sur, o de la Pabostr├¡a de la Catedral de El Salvador, medieval acceso en desuso. La denominaci├│n de "pabostr├¡a" hac├¡a referencia a la cercana residencia del encargado de la hacienda y los bienes temporales de la catedral. Desde antiguo, este cargo fue teniendo varias denominaciones: "Procuraci├│n", "Mensa Com├║n", "Mensa Capitular", "Prepositura", y "Pabostr├¡a". El que tiene la llave de la caja, en plata.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65446100, -0.87629900, '0101000020E6100000658F5033A40AECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15760216592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15760216592.webp', 'https://www.flickr.com/photos/zaragozaantigua/15760216592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22128, 'Pl. de la Seo c.1959', 'Plaza de La Seo. Al fondo, el edificio sin terminar del nuevo Ayuntamiento, y el Pilar. En primer t├®rmino, las v├¡as de la tranviaria l├¡nea del Arrabal. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159778261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159778261.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159778261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22200, 'Pl. de La Seo 1954', 'Imagen de la plaza de la Seo capturada desde los jardines que hubiera en la ampliada plaza del Pilar, en el tramo desde la nueva Casa Consistorial, y hasta la calle de Don Jaime I, al fondo. Por esta calle, precisamente, transita un troleb├║s (posiblemente el n┬║ 15, un Vectra-Escoriaza) de la l├¡nea del G├íllego, en su retorno a la terminal del Coso. Fuente visual: archivo Heraldo de Arag├│n, en "Padre Ebro. El r├¡o Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33572915190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33572915190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33572915190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22359, 'Plaza de La Seo 1961', '"Plaza de la Catedral", ├│leo sobre lienzo, Alberto P├®rez Piqueras, 1961. Premio Goya en el concurso Arte zaragozano actual de 1962. Representaci├│n neocubista de la plaza de La Seo de Zaragoza, con el Palacio Arzobispal al fondo, la fuente de la Samaritana y la entrada a la catedral. Fuente: Colecci├│n del Ayuntamiento de Zaragoza.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST├ôRICO', 41.65530900, -0.87635300, '0101000020E6100000310C5872150BECBF22E3512AE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20886096742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20886096742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20886096742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22833, 'Foro Romano c.1989', 'En 1980, durante los trabajos de restauraci├│n en La Seo, se hall├│ una cloaca cuya funci├│n era la de recoger las aguas ca├¡das de la plaza del templo del Foro romano. Ese mismo a├▒o se hallaba tambi├®n otra cloaca en la calle de Don Jaime. En 1982, los arque├│logos localizaron el sistema de desag├╝e de las termas que se hallan (musealizadas) en la calle de San Juan y San Pedro. Entre 1988 y 1994, con las excavaciones arqueol├│gicas en la plaza de La Seo (1988-1991) y solares contiguos (1991-1994), se complet├│ el conocimiento de los canales y cloacas al servicio del Foro de Caesaraugusta. Hay 30 cloacas registradas arqueol├│gicamente en la ciudad, cuyo conjunto es superior a los 600 metros de longitud. En la imagen, el subsuelo de la Plaza de la Seo levantado, excavado, y estudiado. A la izquierda, fuera del per├¡metro arqueol├│gico, la base de la Torre de la Seo.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65524600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFDB6AD619DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754262510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754262510.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754262510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22911, 'Plaza La Seo c.1988', 'Excavaci├│n arqueol├│gica del foro romano en la plaza de La Seo. Al fondo, en el centro, calle de Don Jaime I. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150712055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150712055.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150712055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22912, 'Plaza La Seo c.1988', 'Excavaci├│n arqueol├│gica del foro romano. Al fondo, la plaza del Pilar. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23186574831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23186574831.webp', 'https://www.flickr.com/photos/zaragozaantigua/23186574831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22935, 'La Seo 1989', 'Vista nocturna de las excavaciones arqueol├│gicas en la plaza de La Seo, con la catedral al fondo, en 1989. Esta prospecci├│n tuvo lugar entre 1988 y 1991, dando como resultado el museo del Foro Romano. Fuente: "La plaza de La Seo. Zaragoza. Investigaciones Hist├│rico-Arqueol├│gicas". Ayuntamiento de Zaragoza, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32171401686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32171401686.webp', 'https://www.flickr.com/photos/zaragozaantigua/32171401686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23850, 'Pl. de la Seo c.1955', 'Imagen de la nocturna procesionaria confesional del Rosario de Cristal, con detalle del "paso" del legendario (fant├ístico) ni├▒o-m├írtir Dominguito de Val, santificado por la rama m├ís antisemita y medieval del catolicismo, que lo mantiene en su devocionario aun despu├®s del Concilio Vaticano II. A su vera, sus patrocinados y canoros "infanticos". La captura se ha realizado en la plaza de la Seo, junto a las desaparecidas Casas de los Infantes de la Seo, que quedan a la izquierda, fuera de plano. Al fondo, a la derecha, las a├®reas y visuales jaculatorias de ne├│n instaladas en el templo metropolitano del Pilar al comienzo de la d├®cada, para facilitar el acompa├▒amiento a la jaculatoria oral que suena, tres veces al d├¡a, desde el a├▒o del se├▒or de 1940, A├▒o II de la Victoria. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26620438382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26620438382.webp', 'https://www.flickr.com/photos/zaragozaantigua/26620438382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23994, 'Milagro del Ni├▒o-Hostia 1427', 'Pintura del siglo XVII situada en el pa├▒o lateral izquierdo de la capilla de Santo Dominguito de Val de la Seo de Zaragoza, atribuida por Jos├® Cam├│n Aznar a Bartolom├® Vicente. Procesi├│n en la plaza del la Seo de Zaragoza, en la que el arzobispo Alonso de Arg├╝ello, que lo fue entre 1419 y 1429, porta en brazos bajo palio al Ni├▒o Jes├║s, para llevarlo a la catedral. La leyenda narra que una mujer casada consult├│ a un alfaqu├¡ (doctor en leyes musulm├ín, considerado mago) para eliminar los malos tratos que le propinaba su marido. El remedio aconsejado fue procurarse una hostia consagrada. La mujer comulg├│ en San Miguel sin tragarse la hostia, y la meti├│ en un cofre. Al abrirlo hab├¡a un ni├▒o, que el alfaqu├¡ orden├│ quemar. El ni├▒o sali├│ ileso y se lo contaron al obispo, que organiz├│ la procesi├│n. Dejaron al ni├▒o en el altar de la capilla de San Valero y al d├¡a siguiente en una misa, el ni├▒o se volvi├│ a convertir en hostia y el obispo se la trag├│. En la imagen, la comitiva municipal sigue al palio detr├ís de un grupo de capitulares. A la derecha, los maceros. Al fondo, la supuesta puerta de la Seo, aunque la c├║pula que se ve detr├ís recuerda a la que ten├¡a la Diputaci├│n del Reino. Fuente visual: "El municipio en Arag├│n", DPZ, 2004.', 1427, 1427, 1427, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20549754211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20549754211.webp', 'https://www.flickr.com/photos/zaragozaantigua/20549754211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24227, 'Pl. de la Seo c.1955', '"Rosario de Cristal. Paso de Santo Dominguito de Val. Infanticos. Gente". De las antiguas (y desaparecidas) Casas de los Infantes de la Seo, en la plaza de la Seo, sale el procesional y confesional paso del legendario ni├▒o-m├írtir. El artificio luminario para capturar la nocturna escena atrae miradas y gestos. La del guardia, no. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65504000, -0.87637300, '0101000020E6100000F71DC3633F0BECBF32C9C859D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22463231459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22463231459.webp', 'https://www.flickr.com/photos/zaragozaantigua/22463231459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23685, 'Aer├│dromo Sanjurjo 1939', 'Imagen capturada en el Aer├│dromo Sanjurjo y centrada en un aeroplano alem├ín modelo Messerschmitt Bf 108 B, utilizado en funciones de comunicaci├│n, enlace y correo por el Grupo de Bombardeo K-88 de la Legi├│n Condor. Desde finales de 1937, durante la Batalla de Teruel, y hasta la campa├▒a de Catalu├▒a, a principios de 1939, este fue uno de los aer├│dromos utilizados por el contingente alem├ín enviado por la Alemania nazi para respaldar a los sublevados nacionalistas en la guerra civil, sobre todo como base de bombarderos.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49561229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49561229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/49561229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
